draw((3,3,3)--(3,13,3));
revolution c = cylinder((0,0,3), 1, 10);
revolution c2 = cylinder((0,0,3), 3, 10);
draw(c,black);
draw(c2,black);
draw((3,0,3)--(3,0,13),dashed);
draw((3,3,3)--(3,3,13),dashed);
draw((3,13,3)--(3,13,13),dashed);
draw((3,0,3)--(3,13,3),dashed);
draw((3,0,13)--(3,13,13),dashed);
draw((0,0,3)--(0,0,15),Arrows(TeXHead));
